CREATE DATABASE IF NOT EXISTS manpower_mediator CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE manpower_mediator;
CREATE TABLE roles (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(30) UNIQUE NOT NULL);
INSERT INTO roles(name) VALUES ('admin'),('client'),('supplier');
CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY,role_id INT NOT NULL,name VARCHAR(100) NOT NULL,email VARCHAR(150) UNIQUE NOT NULL,password VARCHAR(255) NOT NULL,status TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(role_id) REFERENCES roles(id));
INSERT INTO users(role_id,name,email,password) VALUES (1,'Administrator','admin@demo.com','$2y$12$Z4BFsFYzrP93tQuSpQCyOe5Xg/bxbFo6jgEhydzwcS/AUn2f5gvpS');
CREATE TABLE clients (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,company_name VARCHAR(150),contact_person VARCHAR(100),mobile VARCHAR(20),address TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE suppliers (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,vendor_name VARCHAR(150),contact_person VARCHAR(100),mobile VARCHAR(20),gst_no VARCHAR(30),services TEXT,status TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE requirements (id INT AUTO_INCREMENT PRIMARY KEY,client_id INT NULL,manpower_type VARCHAR(100) NOT NULL,location VARCHAR(200) NOT NULL,number_of_staff INT NOT NULL,shift_timing VARCHAR(100),duration VARCHAR(100),budget DECIMAL(12,2) NULL,description TEXT,status ENUM('new','forwarded','quoted','approved','deployed','closed') DEFAULT 'new',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(client_id) REFERENCES clients(id));
CREATE TABLE requirement_assignments (id INT AUTO_INCREMENT PRIMARY KEY,requirement_id INT NOT NULL,supplier_id INT NOT NULL,status VARCHAR(30) DEFAULT 'sent',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(requirement_id) REFERENCES requirements(id),FOREIGN KEY(supplier_id) REFERENCES suppliers(id));
CREATE TABLE quotations (id INT AUTO_INCREMENT PRIMARY KEY,requirement_id INT NOT NULL,supplier_id INT NOT NULL,amount DECIMAL(12,2) NOT NULL,availability INT DEFAULT 0,remarks TEXT,status VARCHAR(30) DEFAULT 'submitted',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE deployments (id INT AUTO_INCREMENT PRIMARY KEY,requirement_id INT NOT NULL,supplier_id INT NOT NULL,staff_count INT NOT NULL,deployment_date DATE,status VARCHAR(30) DEFAULT 'active',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE payments (id INT AUTO_INCREMENT PRIMARY KEY,requirement_id INT NOT NULL,client_amount DECIMAL(12,2) DEFAULT 0,supplier_amount DECIMAL(12,2) DEFAULT 0,commission DECIMAL(12,2) GENERATED ALWAYS AS (client_amount-supplier_amount) STORED,status VARCHAR(30) DEFAULT 'pending',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
